import React from "react";
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
} from "react-router-dom";
import Homepage from "./pages/Homepage";
import Accounts from "./pages/Accounts";
import Payments from "./pages/Payments";
import Portfolio from "./pages/Portfolio";
import AddTransaction from "./pages/AddTransaction";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Profile from "./pages/Profile";
import InterestCalculatorPanel from "./components/InterestCalculatorPanel";
import Investors from "./pages/Investors";
import AddInvestor from "./pages/AddInvestor";

// Util to check authentication status
function isAuthenticated() {
  return !!localStorage.getItem("token");
}

// Wrapper for protecting routes
function PrivateRoute({ children }) {
  return isAuthenticated() ? children : <Navigate to="/login" replace />;
}

function App() {
  return (
    <Router>
      <Routes>
        {/* Always redirect root (/) to /login */}
        <Route path="/" element={<Navigate to="/login" replace />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />

        {/* All below require authentication */}
        <Route
          path="/homepage"
          element={
            <PrivateRoute>
              <Homepage />
            </PrivateRoute>
          }
        />
        <Route
          path="/accounts"
          element={
            <PrivateRoute>
              <Accounts />
            </PrivateRoute>
          }
        />
        <Route
          path="/payments"
          element={
            <PrivateRoute>
              <Payments />
            </PrivateRoute>
          }
        />
        <Route
          path="/portfolio"
          element={
            <PrivateRoute>
              <Portfolio />
            </PrivateRoute>
          }
        />
        <Route
          path="/profile"
          element={
            <PrivateRoute>
              <Profile />
            </PrivateRoute>
          }
        />
        <Route
          path="/addtransaction"
          element={
            <PrivateRoute>
              <AddTransaction />
            </PrivateRoute>
          }
        />
        <Route
          path="/investors"
          element={
            <PrivateRoute>
              <Investors />
            </PrivateRoute>
          }
        />
        <Route
          path="/add-investor"
          element={
            <PrivateRoute>
              <AddInvestor />
            </PrivateRoute>
          }
        />
        <Route
          path="/interest-calculator"
          element={
            <PrivateRoute>
              <InterestCalculatorPanel />
            </PrivateRoute>
          }
        />
      </Routes>
    </Router>
  );
}

export default App;
